settings.custom_liquid:
{% if product.metafields.custom.preorder != blank %}
<div class="subtitle">{{ product.metafields.custom.preorder }}<br></div>

{% elsif product.metafields.custom.lotus_light_name != blank %}
<div class="subtitle">Formerly known as: {{ product.metafields.custom.lotus_light_name }}<br></div>

{% elsif product.metafields.my_fields.botanical_name != blank %}
<div class="subtitle">{{ product.metafields.my_fields.botanical_name }} <br></div>
  {% else %}

{% endif %}

{% if product.metafields.custom.association != blank %}     
<div class"assoziation">{{ product.metafields.custom.association }}</div>
  {% else %}
{% endif %}

{% if product.metafields.custom.sell_by_date != blank %}
<p>Sell by Date: {{ product.metafields.custom.sell_by_date }}</p>
  {% else %}
{% endif %}

{% if product.description != blank %}
<div class="prod-desc" style="max-width: 1060px; margin: auto;">
{{ product.description }}
        </div>
{% endif %}
